export function nextGeneration(cells: Cell[]): Cell[] {
  const aliveCells = new Set(cells.map(cellKey));
  const countLiveNeighbors = ([x, y]: Cell): number =>
    NEIGHBOR_OFFSETS.filter(([dx, dy]) => aliveCells.has(cellKey([x + dx, y + dy]))).length;

  const survivors = cells.filter((cell) => countLiveNeighbors(cell) >= 2);

  const candidateDeadCells = new Map<string, Cell>();
  for (const [x, y] of cells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const neighbor: Cell = [x + dx, y + dy];
      const k = cellKey(neighbor);
      if (!aliveCells.has(k)) candidateDeadCells.set(k, neighbor);
    }
  }
  const births: Cell[] = [];
  for (const cell of candidateDeadCells.values()) {
    if (countLiveNeighbors(cell) === 3) births.push(cell);
  }

  return [...survivors, ...births];
}

